sql:
SELECT name
FROM restaurants
WHERE cuisine_type = 'Italian' AND price_range = 'Cheap';

SELECT restaurants.name, ratings.average_rating
FROM restaurants
INNER JOIN ratings ON restaurants.restaurant_id = ratings.restaurant_id;

SELECT restaurants.name, restaurants.address, analytics.total_views
FROM restaurants
JOIN analytics ON restaurants.restaurant_id = analytics.restaurant_id;

